  constructor(props) {
    super(props);
    this.state = {
        expanded: true,
    }
    this.handleClick = this.handleClick.bind(this)
  }

  handleClick() {
      this.setState(state => ({
          expanded: !this.state.expanded,
      }));
  }

  collapse() {

  }

  render() {
    return (
      <div id='outer' onClick={() => this.handleClick()}>
          <TopBar title={this.props.title}/>
          <div id='content-holder'>
            <div id='descriptions'>

            </div>
            <div id='timeline'>

            </div>
            <div id='stories'>
                <Article index={1}/>
            </div>
          </div>
      </div>
    );
  }
}

function TopBar(props) {
    return (
        <div id='topBar'>
             <h2>{props.title}</h2>
        </div>
    );
}

