}


const Portfolio = () => {
    return (
        <div id='portfolio'>
            <Section title='Reporting on UCLA student at the U.S. Capitol riots'/>
            <Section title='Data reporting'/>
            <Section title='Reporting on COVID-19 across LA County and at UCLA'/>
            <Section title='Other daily reporting'/>
        </div>
    );
}

export default Portfolio;
